'use client';

import { useState } from 'react';
import Image from 'next/image';
import Link from 'next/link';
import { AnimatePresence, motion } from 'framer-motion';
import {
  ShoppingCart,
  Plus,
  Minus,
  X,
  ArrowUpRight,
  ArrowRight,
  Check,
} from 'lucide-react';
import ScrollReveal from '@/components/ScrollReveal';
import SectionHeading from '@/components/SectionHeading';
import { PRINT_PRODUCTS } from '@/lib/constants';

interface CartItem {
  productId: string;
  productName: string;
  size: string;
  price: number;
  quantity: number;
}

export default function PrintStorePage() {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [cartOpen, setCartOpen] = useState(false);

  const addToCart = (
    productId: string,
    productName: string,
    size: string,
    price: number
  ) => {
    setCart((prev) => {
      const existing = prev.find(
        (item) => item.productId === productId && item.size === size
      );
      if (existing) {
        return prev.map((item) =>
          item.productId === productId && item.size === size
            ? { ...item, quantity: item.quantity + 1 }
            : item
        );
      }
      return [...prev, { productId, productName, size, price, quantity: 1 }];
    });
    setCartOpen(true);
  };

  const removeFromCart = (productId: string, size: string) => {
    setCart((prev) =>
      prev.filter(
        (item) => !(item.productId === productId && item.size === size)
      )
    );
  };

  const updateQuantity = (productId: string, size: string, delta: number) => {
    setCart((prev) =>
      prev
        .map((item) =>
          item.productId === productId && item.size === size
            ? { ...item, quantity: Math.max(0, item.quantity + delta) }
            : item
        )
        .filter((item) => item.quantity > 0)
    );
  };

  const total = cart.reduce((sum, item) => sum + item.price * item.quantity, 0);
  const itemCount = cart.reduce((s, i) => s + i.quantity, 0);

  return (
    <>
      {/* Hero */}
      <section className="bg-bg pt-40 pb-16 px-6">
        <div className="max-w-3xl mx-auto text-center">
          <ScrollReveal>
            <p className="text-gold text-[11px] tracking-[0.2em] uppercase font-medium mb-5">
              Fine Art
            </p>
            <h1 className="font-serif text-5xl md:text-7xl text-text-primary mb-4">
              Print <span className="italic text-gold">Store</span>
            </h1>
            <p className="text-text-secondary text-base max-w-md mx-auto leading-relaxed">
              Transform your favorite photographs into museum-quality art that
              will be cherished for generations.
            </p>
          </ScrollReveal>
        </div>
      </section>

      {/* Cart FAB */}
      <button
        onClick={() => setCartOpen(!cartOpen)}
        className="fixed bottom-8 right-8 z-50 w-14 h-14 bg-text-primary text-white rounded-full flex items-center justify-center shadow-lg hover:bg-gold transition-colors duration-300"
      >
        <ShoppingCart size={20} />
        {itemCount > 0 && (
          <span className="absolute -top-1 -right-1 w-5 h-5 bg-gold text-white text-[10px] rounded-full flex items-center justify-center font-bold">
            {itemCount}
          </span>
        )}
      </button>

      {/* Cart Sidebar */}
      <AnimatePresence>
        {cartOpen && (
          <>
            {/* Backdrop */}
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="fixed inset-0 z-40 bg-black/40"
              onClick={() => setCartOpen(false)}
            />
            {/* Panel */}
            <motion.div
              initial={{ x: '100%' }}
              animate={{ x: 0 }}
              exit={{ x: '100%' }}
              transition={{ type: 'spring', damping: 25, stiffness: 200 }}
              className="fixed top-0 right-0 w-full max-w-md h-full z-50 bg-white border-l border-border overflow-auto"
            >
              <div className="p-8">
                {/* Cart Header */}
                <div className="flex items-center justify-between mb-8">
                  <h3 className="font-serif text-2xl text-text-primary">
                    Your Cart
                  </h3>
                  <button
                    onClick={() => setCartOpen(false)}
                    className="w-9 h-9 rounded-full bg-bg-light flex items-center justify-center text-text-tertiary hover:text-text-primary transition-colors"
                  >
                    <X size={16} />
                  </button>
                </div>

                {cart.length === 0 ? (
                  <div className="text-center py-16">
                    <ShoppingCart
                      size={32}
                      className="text-text-tertiary mx-auto mb-4"
                    />
                    <p className="text-text-tertiary text-sm">
                      Your cart is empty
                    </p>
                  </div>
                ) : (
                  <>
                    {/* Cart Items */}
                    <div className="space-y-4 mb-8">
                      {cart.map((item) => (
                        <div
                          key={`${item.productId}-${item.size}`}
                          className="flex items-center gap-4 p-4 rounded-xl bg-bg-light"
                        >
                          <div className="flex-1 min-w-0">
                            <p className="text-text-primary text-sm font-medium truncate">
                              {item.productName}
                            </p>
                            <p className="text-text-tertiary text-xs">
                              {item.size}
                            </p>
                          </div>
                          <div className="flex items-center gap-2">
                            <button
                              onClick={() =>
                                updateQuantity(
                                  item.productId,
                                  item.size,
                                  -1
                                )
                              }
                              className="w-7 h-7 rounded-full bg-white border border-border flex items-center justify-center text-text-tertiary hover:text-text-primary transition-colors"
                            >
                              <Minus size={12} />
                            </button>
                            <span className="text-text-primary text-sm w-6 text-center">
                              {item.quantity}
                            </span>
                            <button
                              onClick={() =>
                                updateQuantity(item.productId, item.size, 1)
                              }
                              className="w-7 h-7 rounded-full bg-white border border-border flex items-center justify-center text-text-tertiary hover:text-text-primary transition-colors"
                            >
                              <Plus size={12} />
                            </button>
                          </div>
                          <p className="text-gold text-sm w-16 text-right font-medium">
                            ${(item.price * item.quantity).toLocaleString()}
                          </p>
                          <button
                            onClick={() =>
                              removeFromCart(item.productId, item.size)
                            }
                            className="text-text-tertiary hover:text-red-500 transition-colors"
                          >
                            <X size={14} />
                          </button>
                        </div>
                      ))}
                    </div>

                    {/* Total */}
                    <div className="border-t border-border pt-5 mb-6">
                      <div className="flex justify-between items-center">
                        <span className="text-text-secondary text-sm">
                          Total
                        </span>
                        <span className="text-2xl font-serif text-text-primary">
                          ${total.toLocaleString()}
                        </span>
                      </div>
                    </div>

                    {/* Checkout */}
                    <button
                      onClick={() =>
                        alert(
                          'Checkout coming soon! In production, this would use Stripe.'
                        )
                      }
                      className="btn-primary w-full py-4 text-sm"
                    >
                      Checkout
                      <ArrowUpRight size={14} />
                    </button>

                    <p className="text-text-tertiary text-xs text-center mt-4">
                      Secure checkout powered by Stripe
                    </p>
                  </>
                )}
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>

      {/* Products Grid */}
      <section className="py-24 px-6 bg-bg-white">
        <div className="max-w-[1200px] mx-auto">
          <ScrollReveal>
            <SectionHeading
              subtitle="Products"
              title="Fine Art Prints & Albums"
              description="Museum-quality prints, handcrafted albums, and wall art that will be cherished for generations."
            />
          </ScrollReveal>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {PRINT_PRODUCTS.map((product, i) => (
              <ScrollReveal key={product.id} delay={i * 0.1}>
                <div className="card overflow-hidden">
                  {/* Product Image */}
                  <div className="relative aspect-[16/10] overflow-hidden">
                    <Image
                      src={product.image}
                      alt={product.name}
                      fill
                      className="object-cover transition-transform duration-700 hover:scale-105"
                      loading="lazy"
                      sizes="(max-width: 768px) 100vw, 50vw"
                    />
                  </div>

                  {/* Product Info */}
                  <div className="p-8">
                    <h3 className="font-serif text-2xl text-text-primary mb-2">
                      {product.name}
                    </h3>
                    <p className="text-text-secondary text-sm leading-relaxed mb-6">
                      {product.description}
                    </p>

                    {/* Sizes */}
                    <div className="space-y-2">
                      {product.sizes.map((size) => (
                        <div
                          key={size.size}
                          className="flex items-center justify-between p-4 rounded-xl bg-bg-light hover:bg-bg transition-colors"
                        >
                          <span className="text-text-secondary text-sm">
                            {size.size}
                          </span>
                          <div className="flex items-center gap-4">
                            <span className="text-text-primary text-sm font-medium">
                              ${size.price}
                            </span>
                            <button
                              onClick={() =>
                                addToCart(
                                  product.id,
                                  product.name,
                                  size.size,
                                  size.price
                                )
                              }
                              className="px-4 py-2 rounded-full text-xs font-medium bg-text-primary text-white hover:bg-gold transition-colors duration-300"
                            >
                              Add to Cart
                            </button>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              </ScrollReveal>
            ))}
          </div>
        </div>
      </section>

      {/* Info Section */}
      <section className="bg-bg py-24 px-6">
        <div className="max-w-[1200px] mx-auto">
          <ScrollReveal>
            <SectionHeading
              subtitle="Quality"
              title="Crafted with Care"
              description="Every print is produced using archival-quality materials and meticulous attention to detail."
            />
          </ScrollReveal>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {[
              {
                title: 'Archival Materials',
                description:
                  'All prints use acid-free, museum-grade paper and inks rated to last 100+ years without fading.',
              },
              {
                title: 'Color Calibrated',
                description:
                  'Each print is individually color-calibrated to ensure perfect tonal accuracy and rich detail.',
              },
              {
                title: 'Hand Inspected',
                description:
                  'Every order is hand-inspected for quality before being carefully packaged and shipped.',
              },
            ].map((item, i) => (
              <ScrollReveal key={i} delay={i * 0.1}>
                <div className="card p-8 h-full">
                  <div className="w-10 h-10 rounded-full bg-gold-bg flex items-center justify-center mb-5">
                    <Check size={18} className="text-gold" />
                  </div>
                  <h3 className="text-lg font-semibold text-text-primary mb-3">
                    {item.title}
                  </h3>
                  <p className="text-text-secondary text-sm leading-relaxed">
                    {item.description}
                  </p>
                </div>
              </ScrollReveal>
            ))}
          </div>
        </div>
      </section>

      {/* CTA */}
      <section className="bg-bg-light py-24 px-6">
        <ScrollReveal>
          <div className="max-w-2xl mx-auto text-center">
            <h2 className="font-serif text-3xl md:text-4xl text-text-primary mb-4">
              Custom Orders <span className="italic text-gold">Welcome</span>
            </h2>
            <p className="text-text-secondary text-sm leading-relaxed max-w-lg mx-auto mb-8">
              Looking for a custom size, special framing, or a large-format
              installation? We&apos;d love to help bring your vision to life.
            </p>
            <Link
              href="/contact"
              className="btn-primary inline-flex items-center gap-2 text-sm"
            >
              Get in Touch
              <ArrowRight size={14} />
            </Link>
          </div>
        </ScrollReveal>
      </section>
    </>
  );
}
