'use client';

interface SectionHeadingProps {
  subtitle?: string;
  title: string;
  description?: string;
  align?: 'left' | 'center';
}

export default function SectionHeading({
  subtitle,
  title,
  description,
  align = 'center',
}: SectionHeadingProps) {
  const isCenter = align === 'center';
  const words = title.split(' ');

  return (
    <div
      className={`max-w-2xl mb-16 md:mb-20 ${
        isCenter ? 'mx-auto text-center' : 'text-left'
      }`}
    >
      {subtitle && (
        <p className="text-gold text-[11px] tracking-[0.2em] uppercase font-medium mb-5">
          {subtitle}
        </p>
      )}
      <h2 className="font-serif text-4xl md:text-5xl lg:text-6xl text-text-primary leading-[1.1] mb-5">
        {words.map((word, i) =>
          i === words.length - 1 ? (
            <span key={i} className="italic text-gold">
              {' '}
              {word}
            </span>
          ) : (
            <span key={i}>
              {i > 0 ? ' ' : ''}
              {word}
            </span>
          )
        )}
      </h2>
      {description && (
        <p className="text-text-secondary text-base leading-relaxed">
          {description}
        </p>
      )}
    </div>
  );
}
